types_and_interfaces.definition:
export type PipelineStatus = 'uploaded' | 'ocr_processing' | 'ocr_done' | 'embedding' | 'embedded' | 'extracting' | 'review_ready' | 'failed';

export interface DashboardSummaryResponse {
  documents_by_status: Record<PipelineStatus, number>;
  unresolved_conflict_count: number;
  recent_documents: Array<{
    document_id: string;
    title: string;
    detected_type: 'sustainability_report' | 'energy_bill' | 'hr_report' | 'financial_statement' | 'other';
    category_id: string | null;
    created_at: string;
  }>;
  recent_reports: Array<{
    report_id: string;
    version: number;
    status: 'draft' | 'final';
    language: string;
    generated_at: string;
  }>;
}

export interface CategoryNode {
  category_id: string;
  name: string;
  path: string;
  parent_category_id: string | null;
  sort_order: number;
  children: CategoryNode[];
}

export interface CategoriesReorderRequest {
  ordered_ids: string[];
  parent_category_id: string | null;
}

export interface PreferencesResponse {
  scope: string;
  preferences: {
    language?: string;
    tone?: string;
    layout?: string;
    section_order?: string[];
    style_rules?: string[];
  };
}

export interface CreateUserRequest {
  email: string;
  role: 'editor' | 'viewer';
}

export interface MergeObservationsRequest {
  observation_ids: string[];
  canonical_label: string;
  canonical_normalized_key: string;
}

export interface ClientPayload {
  client_id: string;
  company_id: string;
  name: string;
  description: string | null;
  created_at: string;
  updated_at?: string;
}

export interface RateLimitResult {
  allowed: boolean;
  remaining: number;
  retryAfterSeconds: number;
}
